'use strict';

const store = new Map();

const CHARSET = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
const CODE_LENGTH = 6;

function generateCode() {
  let code = '';
  for (let i = 0; i < CODE_LENGTH; i++) {
    const idx = Math.floor(Math.random() * CHARSET.length);
    code += CHARSET[idx];
  }
  return code;
}

function generateUniqueCode() {
  let code;
  let attempts = 0;
  do {
    code = generateCode();
    attempts++;
    if (attempts > 1000) {
      throw new Error('Failed to generate unique code after 1000 attempts');
    }
  } while (store.has(code));
  return code;
}

function createShortUrl(originalUrl, customCode, expiresInSeconds) {
  let code;
  if (customCode) {
    if (store.has(customCode)) {
      const err = new Error('Custom code already exists');
      err.code = 'DUPLICATE_CODE';
      throw err;
    }
    code = customCode;
  } else {
    code = generateUniqueCode();
  }

  const now = new Date();
  const expiresAt = expiresInSeconds ? new Date(now.getTime() + expiresInSeconds * 1000) : null;

  store.set(code, {
    code,
    originalUrl,
    clicks: 0,
    createdAt: now.toISOString(),
    expiresAt: expiresAt ? expiresAt.toISOString() : null,
  });

  return code;
}

function getUrl(code) {
  const entry = store.get(code);
  if (!entry) return null;
  return entry;
}

function incrementClick(code) {
  const entry = store.get(code);
  if (!entry) return false;
  entry.clicks += 1;
  store.set(code, entry);
  return true;
}

function getAllUrls() {
  return Array.from(store.values());
}

function deleteUrl(code) {
  if (!store.has(code)) return false;
  store.delete(code);
  return true;
}

function isExpired(entry) {
  if (!entry.expiresAt) return false;
  return new Date() > new Date(entry.expiresAt);
}

module.exports = {
  createShortUrl,
  getUrl,
  incrementClick,
  getAllUrls,
  deleteUrl,
  isExpired,
};

'use strict';

const express = require('express');
const path = require('path');
const storage = require('./storage');

const app = express();
const PORT = process.env.PORT || 3000;

// Middleware
app.use((req, res, next) => {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, DELETE, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  if (req.method === 'OPTIONS') {
    return res.sendStatus(204);
  }
  next();
});

app.use(express.json());
app.use(express.static(path.join(__dirname, 'public')));

// POST /api/shorten
app.post('/api/shorten', (req, res) => {
  const { url, customCode, expiresIn } = req.body;

  if (!url) {
    return res.status(400).json({ error: 'URL is required' });
  }

  // Validate URL
  try {
    new URL(url);
  } catch {
    return res.status(400).json({ error: 'Invalid URL' });
  }

  let code;
  try {
    code = storage.createShortUrl(url, customCode || null, expiresIn || null);
  } catch (err) {
    if (err.code === 'DUPLICATE_CODE') {
      return res.status(409).json({ error: 'Custom code already exists' });
    }
    return res.status(500).json({ error: 'Internal server error' });
  }

  const entry = storage.getUrl(code);
  return res.status(201).json({
    code,
    shortUrl: `http://localhost:${PORT}/${code}`,
    originalUrl: entry.originalUrl,
    expiresAt: entry.expiresAt,
  });
});

// GET /api/urls
app.get('/api/urls', (req, res) => {
  const urls = storage.getAllUrls().map((entry) => ({
    code: entry.code,
    originalUrl: entry.originalUrl,
    shortUrl: `http://localhost:${PORT}/${entry.code}`,
    clicks: entry.clicks,
    createdAt: entry.createdAt,
    expiresAt: entry.expiresAt,
  }));
  return res.json(urls);
});

// GET /api/stats/:code
app.get('/api/stats/:code', (req, res) => {
  const { code } = req.params;
  const entry = storage.getUrl(code);

  if (!entry) {
    return res.status(404).json({ error: 'Short URL not found' });
  }

  return res.json({
    code: entry.code,
    originalUrl: entry.originalUrl,
    shortUrl: `http://localhost:${PORT}/${entry.code}`,
    clicks: entry.clicks,
    createdAt: entry.createdAt,
    expiresAt: entry.expiresAt,
  });
});

// DELETE /api/urls/:code
app.delete('/api/urls/:code', (req, res) => {
  const { code } = req.params;
  const deleted = storage.deleteUrl(code);

  if (!deleted) {
    return res.status(404).json({ error: 'Short URL not found' });
  }

  return res.status(204).send();
});

// GET / — serve index.html
app.get('/', (req, res) => {
  res.sendFile(path.join(__dirname, 'public', 'index.html'));
});

// GET /:code — redirect
app.get('/:code', (req, res) => {
  const { code } = req.params;
  const entry = storage.getUrl(code);

  if (!entry) {
    return res.status(404).json({ error: 'Short URL not found' });
  }

  if (storage.isExpired(entry)) {
    return res.status(410).json({ error: 'Short URL has expired' });
  }

  storage.incrementClick(code);
  return res.redirect(302, entry.originalUrl);
});

app.listen(PORT, () => {
  console.log(`URL Shortener server running on port ${PORT}`);
});

module.exports = app;

/* ============================
   CSS 변수
   ============================ */
:root {
  --color-primary-start: #667eea;
  --color-primary-end: #764ba2;
  --color-primary: #667eea;
  --color-primary-dark: #5a6fd6;
  --color-secondary: #6c757d;
  --color-danger: #e74c3c;
  --color-danger-dark: #c0392b;
  --color-success: #2ecc71;
  --color-success-dark: #27ae60;
  --color-warning: #f39c12;

  --color-bg: #f0f2f5;
  --color-surface: #ffffff;
  --color-border: #e2e8f0;
  --color-text: #2d3748;
  --color-text-muted: #718096;
  --color-text-light: #a0aec0;

  --radius-sm: 6px;
  --radius-md: 10px;
  --radius-lg: 16px;

  --shadow-card: 0 4px 24px rgba(0, 0, 0, 0.08);
  --shadow-btn: 0 2px 8px rgba(102, 126, 234, 0.35);

  --transition: 0.2s ease;
  --font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
}

/* ============================
   리셋 & 기본
   ============================ */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
}

body {
  font-family: var(--font-family);
  background: var(--color-bg);
  color: var(--color-text);
  min-height: 100vh;
  line-height: 1.6;
}

a {
  color: var(--color-primary);
  text-decoration: none;
}

a:hover {
  text-decoration: underline;
}

/* ============================
   헤더
   ============================ */
.header {
  background: linear-gradient(135deg, var(--color-primary-start), var(--color-primary-end));
  color: #fff;
  padding: 48px 24px 40px;
  text-align: center;
  position: relative;
  overflow: hidden;
}

.header::before {
  content: '';
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  background: radial-gradient(circle at 30% 50%, rgba(255,255,255,0.08) 0%, transparent 60%);
  pointer-events: none;
}

.header-inner {
  position: relative;
  z-index: 1;
}

.header-title {
  font-size: 2.2rem;
  font-weight: 700;
  letter-spacing: -0.5px;
  margin-bottom: 8px;
}

.header-subtitle {
  font-size: 1rem;
  opacity: 0.85;
}

/* ============================
   메인 레이아웃
   ============================ */
.main {
  max-width: 860px;
  margin: -24px auto 48px;
  padding: 0 16px;
  display: flex;
  flex-direction: column;
  gap: 24px;
}

/* ============================
   카드
   ============================ */
.card {
  background: var(--color-surface);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-card);
  padding: 32px;
}

.section-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 20px;
}

.section-title {
  font-size: 1.15rem;
  font-weight: 700;
  color: var(--color-text);
  margin-bottom: 20px;
}

.section-header .section-title {
  margin-bottom: 0;
}

/* ============================
   폼 요소
   ============================ */
.form-group {
  display: flex;
  flex-direction: column;
  gap: 6px;
  margin-bottom: 16px;
}

.form-label {
  font-size: 0.875rem;
  font-weight: 600;
  color: var(--color-text);
}

.required {
  color: var(--color-danger);
}

.form-input,
.form-select {
  width: 100%;
  padding: 10px 14px;
  border: 1.5px solid var(--color-border);
  border-radius: var(--radius-sm);
  font-size: 0.95rem;
  font-family: var(--font-family);
  color: var(--color-text);
  background: #fff;
  transition: border-color var(--transition), box-shadow var(--transition);
  outline: none;
}

.form-input::placeholder {
  color: var(--color-text-light);
}

.form-input:focus,
.form-select:focus {
  border-color: var(--color-primary);
  box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.18);
}

.form-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
}

/* ============================
   버튼
   ============================ */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 10px 22px;
  border: none;
  border-radius: var(--radius-sm);
  font-size: 0.95rem;
  font-family: var(--font-family);
  font-weight: 600;
  cursor: pointer;
  transition: background var(--transition), transform var(--transition), box-shadow var(--transition);
  white-space: nowrap;
}

.btn:active {
  transform: translateY(1px);
}

.btn:disabled {
  opacity: 0.65;
  cursor: not-allowed;
  transform: none;
}

.btn-primary {
  background: linear-gradient(135deg, var(--color-primary-start), var(--color-primary-end));
  color: #fff;
  box-shadow: var(--shadow-btn);
}

.btn-primary:hover:not(:disabled) {
  box-shadow: 0 4px 14px rgba(102, 126, 234, 0.5);
  filter: brightness(1.08);
}

.btn-secondary {
  background: var(--color-bg);
  color: var(--color-text);
  border: 1.5px solid var(--color-border);
}

.btn-secondary:hover:not(:disabled) {
  background: var(--color-border);
}

.btn-danger {
  background: var(--color-danger);
  color: #fff;
  padding: 6px 12px;
  font-size: 0.8rem;
}

.btn-danger:hover:not(:disabled) {
  background: var(--color-danger-dark);
}

.btn-copy {
  background: var(--color-success);
  color: #fff;
  padding: 8px 16px;
  font-size: 0.875rem;
  border-radius: var(--radius-sm);
  flex-shrink: 0;
}

.btn-copy:hover:not(:disabled) {
  background: var(--color-success-dark);
}

/* 스피너 버튼 */
.btn-spinner {
  width: 16px;
  height: 16px;
  border: 2px solid rgba(255,255,255,0.4);
  border-top-color: #fff;
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
}

/* ============================
   결과 박스
   ============================ */
.result-box {
  margin-top: 20px;
  padding: 18px 20px;
  background: linear-gradient(135deg, rgba(102,126,234,0.08), rgba(118,75,162,0.08));
  border: 1.5px solid rgba(102,126,234,0.25);
  border-radius: var(--radius-md);
}

.result-label {
  font-size: 0.8rem;
  font-weight: 600;
  color: var(--color-text-muted);
  margin-bottom: 8px;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.result-url-row {
  display: flex;
  align-items: center;
  gap: 12px;
}

.result-url {
  font-size: 1rem;
  font-weight: 600;
  color: var(--color-primary);
  word-break: break-all;
  flex: 1;
}

/* ============================
   테이블
   ============================ */
.table-wrapper {
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
}

.url-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.9rem;
}

.url-table th {
  background: var(--color-bg);
  color: var(--color-text-muted);
  font-weight: 600;
  font-size: 0.8rem;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  padding: 10px 14px;
  text-align: left;
  border-bottom: 2px solid var(--color-border);
  white-space: nowrap;
}

.url-table td {
  padding: 12px 14px;
  border-bottom: 1px solid var(--color-border);
  vertical-align: middle;
  color: var(--color-text);
}

.url-table tbody tr:last-child td {
  border-bottom: none;
}

.url-table tbody tr:hover {
  background: rgba(102,126,234,0.04);
}

.td-original {
  max-width: 200px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  color: var(--color-text-muted);
}

.td-short a {
  color: var(--color-primary);
  font-weight: 600;
}

.td-clicks {
  text-align: center;
  font-weight: 700;
  color: var(--color-primary);
}

.td-expires {
  color: var(--color-text-muted);
  font-size: 0.85rem;
  white-space: nowrap;
}

.empty-msg {
  text-align: center;
  color: var(--color-text-light);
  padding: 40px 0;
  font-size: 0.95rem;
}

.table-loading {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  padding: 40px 0;
  color: var(--color-text-muted);
  font-size: 0.9rem;
}

/* ============================
   통계 조회
   ============================ */
.stats-form-row {
  display: flex;
  gap: 12px;
  margin-bottom: 24px;
}

.stats-form-row .form-input {
  flex: 1;
  margin-bottom: 0;
}

.stats-cards {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
  gap: 16px;
}

.stat-card {
  background: var(--color-bg);
  border-radius: var(--radius-md);
  padding: 16px;
  border: 1px solid var(--color-border);
}

.stat-card-label {
  font-size: 0.75rem;
  font-weight: 600;
  color: var(--color-text-muted);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 6px;
}

.stat-card-value {
  font-size: 0.9rem;
  font-weight: 600;
  color: var(--color-text);
  word-break: break-all;
}

.stat-card-url {
  font-size: 0.8rem;
  font-weight: 400;
  color: var(--color-text-muted);
}

.stat-card-highlight {
  font-size: 1.6rem;
  color: var(--color-primary);
}

/* ============================
   스피너 (독립)
   ============================ */
.spinner {
  display: inline-block;
  width: 18px;
  height: 18px;
  border: 2.5px solid var(--color-border);
  border-top-color: var(--color-primary);
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* ============================
   토스트 알림
   ============================ */
.toast-container {
  position: fixed;
  top: 20px;
  right: 20px;
  z-index: 9999;
  display: flex;
  flex-direction: column;
  gap: 10px;
  pointer-events: none;
}

.toast {
  pointer-events: auto;
  display: flex;
  align-items: center;
  gap: 10px;
  min-width: 260px;
  max-width: 380px;
  padding: 14px 18px;
  border-radius: var(--radius-md);
  box-shadow: 0 4px 20px rgba(0,0,0,0.15);
  font-size: 0.9rem;
  font-weight: 500;
  color: #fff;
  animation: toast-in 0.3s ease forwards;
}

.toast.toast-success {
  background: var(--color-success);
}

.toast.toast-error {
  background: var(--color-danger);
}

.toast.toast-warning {
  background: var(--color-warning);
}

.toast.toast-fade-out {
  animation: toast-out 0.35s ease forwards;
}

@keyframes toast-in {
  from {
    opacity: 0;
    transform: translateX(40px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

@keyframes toast-out {
  from {
    opacity: 1;
    transform: translateX(0);
  }
  to {
    opacity: 0;
    transform: translateX(40px);
  }
}

/* ============================
   유틸리티
   ============================ */
.hidden {
  display: none !important;
}

/* ============================
   반응형
   ============================ */
@media (max-width: 640px) {
  .header-title {
    font-size: 1.6rem;
  }

  .card {
    padding: 20px 16px;
  }

  .form-row {
    grid-template-columns: 1fr;
  }

  .stats-form-row {
    flex-direction: column;
  }

  .stats-cards {
    grid-template-columns: 1fr 1fr;
  }

  .result-url-row {
    flex-direction: column;
    align-items: flex-start;
  }

  .btn-copy {
    width: 100%;
    justify-content: center;
  }
}

@media (max-width: 400px) {
  .stats-cards {
    grid-template-columns: 1fr;
  }

  .url-table th,
  .url-table td {
    padding: 8px 10px;
  }
}

'use strict';

const BASE_URL = window.location.origin;

/* ============================
   유틸리티
   ============================ */

function showToast(message, type = 'success') {
  const container = document.getElementById('toast-container');
  const toast = document.createElement('div');
  toast.className = `toast toast-${type}`;
  toast.textContent = message;
  container.appendChild(toast);

  const duration = 3000;
  setTimeout(() => {
    toast.classList.add('toast-fade-out');
    toast.addEventListener('animationend', () => toast.remove());
  }, duration);
}

function setLoading(btn, loading) {
  const text = btn.querySelector('.btn-text');
  const spinner = btn.querySelector('.btn-spinner');
  if (loading) {
    btn.disabled = true;
    if (text) text.classList.add('hidden');
    if (spinner) spinner.classList.remove('hidden');
  } else {
    btn.disabled = false;
    if (text) text.classList.remove('hidden');
    if (spinner) spinner.classList.add('hidden');
  }
}

function formatDate(dateStr) {
  if (!dateStr) return '없음';
  try {
    return new Date(dateStr).toLocaleString('ko-KR');
  } catch {
    return dateStr;
  }
}

function truncate(str, max = 40) {
  if (!str) return '';
  return str.length > max ? str.slice(0, max) + '...' : str;
}

/* ============================
   API 호출
   ============================ */

async function apiShortenUrl(url, customCode, expiresIn) {
  const body = { url };
  if (customCode) body.customCode = customCode;
  if (expiresIn) body.expiresIn = Number(expiresIn);

  const res = await fetch(`${BASE_URL}/api/shorten`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  });

  const data = await res.json();
  if (!res.ok) throw new Error(data.error || data.message || '단축 URL 생성에 실패했습니다.');
  return data;
}

async function apiFetchUrls() {
  const res = await fetch(`${BASE_URL}/api/urls`);
  const data = await res.json();
  if (!res.ok) throw new Error(data.error || data.message || '목록을 불러오지 못했습니다.');
  return data;
}

async function apiDeleteUrl(code) {
  const res = await fetch(`${BASE_URL}/api/urls/${code}`, { method: 'DELETE' });
  if (!res.ok) {
    const data = await res.json().catch(() => ({}));
    throw new Error(data.error || data.message || '삭제에 실패했습니다.');
  }
}

async function apiFetchStats(code) {
  const res = await fetch(`${BASE_URL}/api/stats/${code}`);
  const data = await res.json();
  if (!res.ok) throw new Error(data.error || data.message || '통계를 불러오지 못했습니다.');
  return data;
}

/* ============================
   섹션 1: URL 단축
   ============================ */

function initShortenForm() {
  const form = document.getElementById('shorten-form');
  const btn = document.getElementById('shorten-btn');
  const resultBox = document.getElementById('result-box');
  const resultUrlEl = document.getElementById('result-url');
  const copyBtn = document.getElementById('copy-btn');

  form.addEventListener('submit', async (e) => {
    e.preventDefault();

    const url = form.url.value.trim();
    const customCode = form.customCode.value.trim();
    const expiresIn = form.expiresIn.value;

    if (!url) {
      showToast('원본 URL을 입력해주세요.', 'warning');
      return;
    }

    setLoading(btn, true);
    try {
      const data = await apiShortenUrl(url, customCode, expiresIn);
      const shortUrl = data.shortUrl || `${BASE_URL}/${data.code}`;

      resultUrlEl.textContent = shortUrl;
      resultUrlEl.href = shortUrl;
      resultBox.classList.remove('hidden');
      showToast('단축 URL이 생성되었습니다!', 'success');
      form.reset();

      // 목록 새로고침
      loadUrlList();
    } catch (err) {
      showToast(err.message, 'error');
    } finally {
      setLoading(btn, false);
    }
  });

  copyBtn.addEventListener('click', async () => {
    const url = resultUrlEl.textContent;
    try {
      await navigator.clipboard.writeText(url);
      showToast('클립보드에 복사되었습니다.', 'success');
    } catch {
      showToast('복사에 실패했습니다. 직접 복사해주세요.', 'warning');
    }
  });
}

/* ============================
   섹션 2: URL 목록
   ============================ */

async function loadUrlList() {
  const tbody = document.getElementById('url-tbody');
  const emptyMsg = document.getElementById('empty-msg');
  const loadingEl = document.getElementById('table-loading');
  const tableEl = document.getElementById('url-table');

  tableEl.classList.add('hidden');
  emptyMsg.classList.add('hidden');
  loadingEl.classList.remove('hidden');

  try {
    const data = await apiFetchUrls();
    const urls = Array.isArray(data) ? data : (data.urls || data.data || []);

    loadingEl.classList.add('hidden');

    if (!urls.length) {
      emptyMsg.classList.remove('hidden');
      return;
    }

    tableEl.classList.remove('hidden');
    tbody.innerHTML = '';

    urls.forEach((item) => {
      const code = item.code || item.shortCode || item.id;
      const shortUrl = item.shortUrl || `${BASE_URL}/${code}`;
      const expiresAt = item.expiresAt || item.expires_at;

      const tr = document.createElement('tr');
      tr.innerHTML = `
        <td class="td-original" title="${item.originalUrl || item.url || ''}">
          ${truncate(item.originalUrl || item.url || '', 40)}
        </td>
        <td class="td-short">
          <a href="${shortUrl}" target="_blank" rel="noopener noreferrer">${shortUrl}</a>
        </td>
        <td class="td-clicks">${item.clicks ?? item.clickCount ?? 0}</td>
        <td class="td-expires">${formatDate(expiresAt)}</td>
        <td>
          <button class="btn btn-danger" data-code="${code}">삭제</button>
        </td>
      `;

      const deleteBtn = tr.querySelector('.btn-danger');
      deleteBtn.addEventListener('click', () => handleDelete(code, tr));

      tbody.appendChild(tr);
    });
  } catch (err) {
    loadingEl.classList.add('hidden');
    showToast(err.message, 'error');
  }
}

async function handleDelete(code, tr) {
  if (!confirm(`'${code}' 단축 URL을 삭제하시겠습니까?`)) return;
  try {
    await apiDeleteUrl(code);
    tr.remove();
    showToast('삭제되었습니다.', 'success');

    const tbody = document.getElementById('url-tbody');
    if (!tbody.children.length) {
      document.getElementById('url-table').classList.add('hidden');
      document.getElementById('empty-msg').classList.remove('hidden');
    }
  } catch (err) {
    showToast(err.message, 'error');
  }
}

function initUrlList() {
  const refreshBtn = document.getElementById('refresh-btn');
  refreshBtn.addEventListener('click', () => loadUrlList());
  loadUrlList();
}

/* ============================
   섹션 3: 통계 조회
   ============================ */

function initStats() {
  const statsBtn = document.getElementById('stats-btn');
  const statsCodeInput = document.getElementById('stats-code');
  const statsCards = document.getElementById('stats-cards');

  statsBtn.addEventListener('click', async () => {
    const code = statsCodeInput.value.trim();
    if (!code) {
      showToast('단축 코드를 입력해주세요.', 'warning');
      return;
    }

    setLoading(statsBtn, true);
    statsCards.classList.add('hidden');

    try {
      const data = await apiFetchStats(code);
      const shortUrl = data.shortUrl || `${BASE_URL}/${code}`;
      const expiresAt = data.expiresAt || data.expires_at;
      const createdAt = data.createdAt || data.created_at;

      document.getElementById('stat-original-url').textContent = data.originalUrl || data.url || '-';
      document.getElementById('stat-short-url').textContent = shortUrl;
      document.getElementById('stat-clicks').textContent = data.clicks ?? data.clickCount ?? 0;
      document.getElementById('stat-created-at').textContent = formatDate(createdAt);
      document.getElementById('stat-expires-at').textContent = formatDate(expiresAt);

      statsCards.classList.remove('hidden');
    } catch (err) {
      showToast(err.message, 'error');
    } finally {
      setLoading(statsBtn, false);
    }
  });

  // Enter 키 지원
  statsCodeInput.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') statsBtn.click();
  });
}

/* ============================
   초기화
   ============================ */

document.addEventListener('DOMContentLoaded', () => {
  initShortenForm();
  initUrlList();
  initStats();
});

